{
  "name": "Daily Store Report → LINE WORKS",
  "nodes": [
    {
      "parameters": {},
      "type": "n8n-nodes-base.manualTrigger",
      "typeVersion": 1,
      "position": [-400, 300],
      "id": "a1b2c3d4-0001-0001-0001-000000000001",
      "name": "手動実行（テスト用）"
    },
    {
      "parameters": {
        "rule": {
          "interval": [
            {
              "field": "cronExpression",
              "expression": "0 9 * * *"
            }
          ]
        }
      },
      "type": "n8n-nodes-base.scheduleTrigger",
      "typeVersion": 1.2,
      "position": [-400, 500],
      "id": "a1b2c3d4-0001-0001-0001-000000000002",
      "name": "毎朝9時実行"
    },
    {
      "parameters": {
        "projectId": {
          "__rl": true,
          "mode": "id",
          "value": "YOUR_BQ_PROJECT_ID"
        },
        "sqlQuery": "SELECT\n  store_id,\n  store_name,\n  CAST(date AS STRING) AS date,\n  sales,\n  visits,\n  new_members,\n  sales_diff_pct,\n  visits_diff_pct,\n  new_members_diff_pct\nFROM `YOUR_BQ_PROJECT_ID.report.daily_store_summary`\nORDER BY sales DESC",
        "options": {
          "location": "asia-northeast1"
        }
      },
      "type": "n8n-nodes-base.googleBigQuery",
      "typeVersion": 2.1,
      "position": [-100, 400],
      "id": "a1b2c3d4-0001-0001-0001-000000000003",
      "name": "BQ: daily_store_summary を取得"
    },
    {
      "parameters": {
        "jsCode": "const items = $input.all();\n\nif (!items || items.length === 0) {\n  throw new Error('BigQueryからデータが取得できませんでした。');\n}\n\nconst rawDate = items[0] && items[0].json && items[0].json.date;\nconst date = rawDate\n  ? (typeof rawDate === 'string' ? rawDate : String(rawDate))\n  : new Date(Date.now() - 86400000).toISOString().slice(0, 10);\n\nfunction diffColor(pct) {\n  if (pct === null || pct === undefined || pct === '') return '#888888';\n  return Number(pct) >= 0 ? '#22BB33' : '#FF4444';\n}\n\nfunction diffText(pct) {\n  if (pct === null || pct === undefined || pct === '') return 'N/A';\n  const n = Number(pct);\n  return (n >= 0 ? '+' : '') + n.toFixed(1) + '%';\n}\n\nfunction formatSales(v) {\n  const n = Number(v) || 0;\n  if (n >= 100000000) return '¥' + (n / 100000000).toFixed(1) + '億';\n  if (n >= 10000) return '¥' + Math.floor(n / 10000) + '万';\n  return '¥' + n.toLocaleString('ja-JP');\n}\n\nconst headerRow = {\n  type: 'box',\n  layout: 'horizontal',\n  contents: [\n    { type: 'text', text: '店舗名', flex: 4, weight: 'bold', size: 'xs', color: '#555555' },\n    { type: 'text', text: '売上', flex: 3, weight: 'bold', size: 'xs', color: '#555555', align: 'end' },\n    { type: 'text', text: '来店', flex: 2, weight: 'bold', size: 'xs', color: '#555555', align: 'end' },\n    { type: 'text', text: '新規', flex: 2, weight: 'bold', size: 'xs', color: '#555555', align: 'end' }\n  ]\n};\n\nconst storeRows = [];\nfor (const item of items) {\n  const d = item.json;\n  storeRows.push(\n    { type: 'separator', margin: 'sm' },\n    {\n      type: 'box',\n      layout: 'horizontal',\n      margin: 'sm',\n      contents: [\n        { type: 'text', text: String(d.store_name || d.store_id || '不明'), flex: 4, size: 'sm', wrap: true },\n        { type: 'text', text: formatSales(d.sales), flex: 3, size: 'sm', align: 'end' },\n        { type: 'text', text: (d.visits || 0) + '名', flex: 2, size: 'sm', align: 'end' },\n        { type: 'text', text: (d.new_members || 0) + '名', flex: 2, size: 'sm', align: 'end' }\n      ]\n    },\n    {\n      type: 'box',\n      layout: 'horizontal',\n      contents: [\n        { type: 'text', text: '', flex: 4, size: 'xxs' },\n        { type: 'text', text: diffText(d.sales_diff_pct), flex: 3, size: 'xxs', align: 'end', color: diffColor(d.sales_diff_pct) },\n        { type: 'text', text: diffText(d.visits_diff_pct), flex: 2, size: 'xxs', align: 'end', color: diffColor(d.visits_diff_pct) },\n        { type: 'text', text: diffText(d.new_members_diff_pct), flex: 2, size: 'xxs', align: 'end', color: diffColor(d.new_members_diff_pct) }\n      ]\n    }\n  );\n}\n\nconst flexContents = {\n  type: 'bubble',\n  size: 'mega',\n  header: {\n    type: 'box',\n    layout: 'vertical',\n    backgroundColor: '#1a73e8',\n    paddingAll: 'lg',\n    contents: [\n      { type: 'text', text: '📊 Daily Store Report', weight: 'bold', color: '#ffffff', size: 'lg' },\n      { type: 'text', text: date + '（前日比）', size: 'sm', color: '#c8d8ff', margin: 'xs' }\n    ]\n  },\n  body: {\n    type: 'box',\n    layout: 'vertical',\n    paddingAll: 'md',\n    contents: [headerRow].concat(storeRows)\n  }\n};\n\nreturn [{\n  json: {\n    flexContents: flexContents,\n    date: date,\n    storeCount: items.length\n  }\n}];"
      },
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [200, 400],
      "id": "a1b2c3d4-0001-0001-0001-000000000004",
      "name": "Flex Message 生成"
    },
    {
      "parameters": {
        "operation": "get",
        "dataTableId": {
          "__rl": true,
          "value": "6iipvD4qo8LCSyrZ",
          "mode": "list",
          "cachedResultName": "line_token"
        },
        "limit": 1
      },
      "type": "n8n-nodes-base.dataTable",
      "typeVersion": 1.1,
      "executeOnce": true,
      "position": [500, 200],
      "id": "a1b2c3d4-0001-0001-0001-000000000005",
      "name": "Get line token"
    },
    {
      "parameters": {
        "assignments": {
          "assignments": [
            {
              "id": "ch-id-001",
              "name": "channel_id",
              "value": "YOUR_DAILY_REPORT_CHANNEL_ID",
              "type": "string"
            }
          ]
        },
        "options": {}
      },
      "type": "n8n-nodes-base.set",
      "typeVersion": 3.4,
      "executeOnce": true,
      "position": [500, 600],
      "id": "a1b2c3d4-0001-0001-0001-000000000006",
      "name": "Daily Report チャネルID（要設定）"
    },
    {
      "parameters": {
        "mode": "combine",
        "combineBy": "combineAll",
        "options": {}
      },
      "type": "n8n-nodes-base.merge",
      "typeVersion": 3.2,
      "position": [800, 300],
      "id": "a1b2c3d4-0001-0001-0001-000000000007",
      "name": "Merge: データ+Token"
    },
    {
      "parameters": {
        "mode": "combine",
        "combineBy": "combineAll",
        "options": {}
      },
      "type": "n8n-nodes-base.merge",
      "typeVersion": 3.2,
      "position": [1100, 400],
      "id": "a1b2c3d4-0001-0001-0001-000000000008",
      "name": "Merge: 全データ合流"
    },
    {
      "parameters": {
        "jsCode": "const d = $input.first().json;\n\nconst body = {\n  content: {\n    type: 'flex',\n    altText: '📊 Daily Store Report ' + d.date + '（' + d.storeCount + '店舗）',\n    contents: d.flexContents\n  }\n};\n\nreturn [{\n  json: {\n    channel_id: d.channel_id,\n    access_token: d.access_token,\n    bodyStr: JSON.stringify(body)\n  }\n}];"
      },
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [1400, 400],
      "id": "a1b2c3d4-0001-0001-0001-000000000009",
      "name": "リクエストボディ生成"
    },
    {
      "parameters": {
        "method": "POST",
        "url": "=https://www.worksapis.com/v1.0/bots/1420096/channels/{{ $json.channel_id }}/messages",
        "sendHeaders": true,
        "headerParameters": {
          "parameters": [
            {
              "name": "Authorization",
              "value": "=Bearer {{ $json.access_token }}"
            },
            {
              "name": "Content-Type",
              "value": "application/json"
            }
          ]
        },
        "sendBody": true,
        "specifyBody": "string",
        "body": "={{ $json.bodyStr }}",
        "options": {
          "response": {
            "response": {
              "fullResponse": true,
              "neverError": true,
              "responseFormat": "json"
            }
          }
        }
      },
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.3,
      "onError": "continueRegularOutput",
      "position": [1700, 400],
      "id": "a1b2c3d4-0001-0001-0001-000000000010",
      "name": "LINE WORKS POST"
    },
    {
      "parameters": {},
      "type": "n8n-nodes-base.noOp",
      "typeVersion": 1,
      "position": [2000, 400],
      "id": "a1b2c3d4-0001-0001-0001-000000000011",
      "name": "完了"
    },
    {
      "parameters": {
        "content": "## ⚙️ 初期設定ガイド\n\n### 1. BigQuery 接続設定\n- `BQ: daily_store_summary を取得` ノードを開き Google BigQuery 認証情報を設定\n- `projectId` を実際の BQ プロジェクト ID に変更\n- SQL 内の `YOUR_BQ_PROJECT_ID` も変更\n\n### 2. LINE WORKS チャネルID\n- `Daily Report チャネルID（要設定）` の `channel_id` を実際の値に変更\n\n### 3. BigQuery テーブル準備\n- TD → BQ Export 後、mart / report テーブルを作成\n\n### 4. テスト実行\n- 手動トリガーで実行 → LINE WORKS にカードが届くことを確認\n- 確認後、Schedule Trigger を有効化",
        "height": 340,
        "width": 460,
        "color": 3
      },
      "type": "n8n-nodes-base.stickyNote",
      "typeVersion": 1,
      "position": [-400, -100],
      "id": "a1b2c3d4-0001-0001-0001-000000000012",
      "name": "Sticky Note: 初期設定ガイド"
    }
  ],
  "connections": {
    "手動実行（テスト用）": {
      "main": [[{ "node": "BQ: daily_store_summary を取得", "type": "main", "index": 0 }]]
