540d', flex: 2, size: 'sm', align: 'end' },\n        { type: 'text', text: (d.new_members || 0) + '\\u540d', flex: 2, size: 'sm', align: 'end' }\n      ]\n    },\n    {\n      type: 'box',\n      layout: 'horizontal',\n      contents: [\n        { type: 'text', text: '', flex: 4, size: 'xxs' },\n        { type: 'text', text: diffText(d.sales_diff_pct), flex: 3, size: 'xxs', align: 'end', color: diffColor(d.sales_diff_pct) },\n        { type: 'text', text: diffText(d.visits_diff_pct), flex: 2, size: 'xxs', align: 'end', color: diffColor(d.visits_diff_pct) },\n        { type: 'text', text: diffText(d.new_members_diff_pct), flex: 2, size: 'xxs', align: 'end', color: diffColor(d.new_members_diff_pct) }\n      ]\n    }\n  );\n}\n\nconst flexContents = {\n  type: 'bubble',\n  size: 'mega',\n  header: {\n    type: 'box',\n    layout: 'vertical',\n    backgroundColor: '#1a73e8',\n    paddingAll: 'lg',\n    contents: [\n      { type: 'text', text: '\\ud83d\\udcca Daily Store Report', weight: 'bold', color: '#ffffff', size: 'lg' },\n      { type: 'text', text: date + '\\uff08\\u524d\\u65e5\\u6bd4\\uff09', size: 'sm', color: '#c8d8ff', margin: 'xs' }\n    ]\n  },\n  body: {\n    type: 'box',\n    layout: 'vertical',\n    paddingAll: 'md',\n    contents: [headerRow].concat(storeRows)\n  }\n};\n\nreturn [{\n  json: {\n    flexContents: flexContents,\n    date: date,\n    storeCount: items.length\n  }\n}];"
